const NAVIGATION_BANNER_BASE64 = "";

const decodeBase64 = (value: string): string => {
  if (typeof atob === "function") {
    return atob(value);
  }

  const maybeBuffer = (globalThis as { Buffer?: { from(data: string, encoding: string): { toString(encoding: string): string } } }).Buffer;
  if (maybeBuffer) {
    return maybeBuffer.from(value, "base64").toString("utf-8");
  }

  return "";
};

export const NAVIGATION_BANNER_HTML = decodeBase64(NAVIGATION_BANNER_BASE64);